tests.setup:
Config = [pi/6, -pi/4, pi/3, -pi/2, pi/8, 0]';
[Ja, Rank] = ComputeAnalyticalJacobian(Config);

ur3e = loadrobot('universalUR3e','DataFormat','column');
Jg = geometricJacobian(ur3e, Config, 'tool0');
T = getTransform(ur3e, Config, 'tool0');
R = T(1:3,1:3);

phi = atan2(R(2,3), R(1,3));
theta = atan2(sqrt(R(1,3)^2 + R(2,3)^2), R(3,3));
psi = atan2(R(3,2), -R(3,1));

Tphi = [
    sin(psi)/sin(theta),   cos(psi)/sin(theta),   0;
    cos(psi),             -sin(psi),             0;
   -sin(psi)*cot(theta),  -cos(psi)*cot(theta),  1
];

Ja_expected = [Tphi zeros(3); zeros(3) eye(3)] * Jg;
